namespace sv_07f5d4a0ab634e76b04beb7b9e4b027b.Models;

public class WizardData
{
    // Step 1 – Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 – Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    /// <summary>Tracks which steps the user has saved (1-based).</summary>
    public HashSet<int> CompletedSteps { get; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_07f5d4a0ab634e76b04beb7b9e4b027b.Models;

namespace sv_07f5d4a0ab634e76b04beb7b9e4b027b.Services;

/// <summary>
/// Singleton store that keeps wizard data keyed by session ID.
/// Survives per-page circuit disposal so data persists across navigations.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId) =>
        _store.GetOrAdd(sessionId, _ => new WizardData());

    public void Remove(string sessionId) =>
        _store.TryRemove(sessionId, out _);
}

