/// at construction time (while HttpContext is still available) and provides
/// access to the user's wizard data in the singleton store.
/// </summary>
public class WizardSession
{
    private readonly WizardStateStore _store;

    public string SessionId { get; }

    public WizardSession(WizardStateStore store, IHttpContextAccessor httpContextAccessor)
    {
        _store = store;
        SessionId = httpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    }

    public WizardData Data => _store.GetOrCreate(SessionId);
}

