@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_07f5d4a0ab634e76b04beb7b9e4b027b.Services.WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.Data.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Wizard.Data.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void Next()
    {
        Wizard.Data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_07f5d4a0ab634e76b04beb7b9e4b027b.Services.WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@for (var i = 0; i < Wizard.Data.JobHistory.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Job @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.Data.JobHistory[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="Wizard.Data.JobHistory[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Duration</label>
            <input class="form-control" @bind="Wizard.Data.JobHistory[index].Duration" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddJob() =>
        Wizard.Data.JobHistory.Add(new());

    private void RemoveJob(int index) =>
        Wizard.Data.JobHistory.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.Data.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject sv_07f5d4a0ab634e76b04beb7b9e4b027b.Services.WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply – References</PageTitle>

<h1>Step 3: References</h1>

@for (var i = 0; i < Wizard.Data.References.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Reference @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="Wizard.Data.References[index].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" type="email" @bind="Wizard.Data.References[index].Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="Wizard.Data.References[index].Relationship" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddRef() =>
        Wizard.Data.References.Add(new());

    private void RemoveRef(int index) =>
        Wizard.Data.References.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        Wizard.Data.CompletedSteps.Add(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inject sv_07f5d4a0ab634e76b04beb7b9e4b027b.Services.WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-4 p-3">
    <h5>Personal Information</h5>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@Wizard.Data.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@Wizard.Data.Email</dd>
    </dl>
</div>

<div class="card mb-4 p-3">
    <h5>Work Experience</h5>
    @if (Wizard.Data.JobHistory.Count == 0)
    {
        <p class="text-muted">No jobs added.</p>
    }
    else
    {
        @foreach (var job in Wizard.Data.JobHistory)
        {
            <div class="border-bottom pb-2 mb-2">
                <strong>@job.Title</strong> at @job.Company <span class="text-muted">(@job.Duration)</span>
            </div>
        }
    }
</div>

<div class="card mb-4 p-3">
    <h5>References</h5>
    @if (Wizard.Data.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    else
    {
        @foreach (var r in Wizard.Data.References)
        {
            <div class="border-bottom pb-2 mb-2">
                <strong>@r.Name</strong> – @r.Email <span class="text-muted">(@r.Relationship)</span>
            </div>
        }
    }
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Your application has been submitted!</div>
}

@code {
    private bool _submitted;

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        Wizard.Data.CompletedSteps.Add(4);
        _submitted = true;
    }
}

