﻿@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject sv_07f5d4a0ab634e76b04beb7b9e4b027b.Services.WizardSession Wizard

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardPage)
            {
                <nav class="wizard-progress">
                    @for (var i = 0; i < _steps.Length; i++)
                    {
                        var step = _steps[i];
                        var stepNum = i + 1;
                        var isCurrent = step.Href == CurrentPath;
                        var isCompleted = Wizard.Data.CompletedSteps.Contains(stepNum);
                        <a href="@step.Href"
                           class="wizard-step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "")">
                            <span class="step-number">@stepNum</span>
                            <span class="step-label">@step.Label</span>
                        </a>
                        @if (stepNum < _steps.Length)
                        {
                            <span class="step-connector @(isCompleted ? "completed" : "")"></span>
                        }
                    }
                </nav>
            }
