/* Wizard progress bar */
.wizard-progress {
    display: flex;
    align-items: center;
    gap: 0;
    width: 100%;
    justify-content: center;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    text-decoration: none;
    color: #6c757d;
    font-size: 0.9rem;
    padding: 0.25rem 0.5rem;
    border-radius: 0.375rem;
    transition: background-color 0.15s;
}

.wizard-step:hover {
    background-color: rgba(0, 0, 0, 0.05);
    text-decoration: none;
}

.wizard-step .step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.6rem;
    height: 1.6rem;
    border-radius: 50%;
    border: 2px solid #adb5bd;
    font-weight: 600;
    font-size: 0.8rem;
}

.wizard-step.current {
    color: #0d6efd;
    font-weight: 600;
}

.wizard-step.current .step-number {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.wizard-step.completed .step-number {
    border-color: #198754;
    background-color: #198754;
    color: #fff;
}

.wizard-step.completed {
    color: #198754;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background-color: #dee2e6;
    flex-shrink: 0;
}

.step-connector.completed {
    background-color: #198754;
}

